mapper.select:
SELECT DISTINCT b.*, a.sell_type, a.deposit, a.sell_num, a.is_on_shelf,c.name mchName FROM lkt_pre_sell_goods a LEFT JOIN lkt_product_list b ON a.product_id = b.id LEFT JOIN lkt_mch c ON b.mch_id = c.id

ORDER BY b.add_date DESC
LIMIT #{page},#{pageSize}

SELECT p.* FROM lkt_pre_sell_goods s LEFT JOIN lkt_product_list p ON s.product_id = p.id

ORDER BY p.add_date DESC
LIMIT #{page},#{pageSize}

where.trim:
AND s.is_display = 1
AND s.is_delete = 0
AND p.recycle = 0
AND p.`status` = 2
AND p.store_id = #{storeId}
AND p.mch_id = #{mchId}
AND p.mch_id = #{storeMchId}
AND p.product_title like CONCAT('%', #{title},'%')

AND b.store_id = #{store_id}
AND b.recycle = 0
AND a.is_delete = 0
AND b.product_class like CONCAT('%-',#{product_class},'-%')
AND b.brand_id = #{brand_id}
AND c.name like CONCAT('%', #{mchName},'%')
AND b.mch_id = #{mch_id}
AND b.status = #{status}
AND a.sell_type = #{sellType}
AND (b.product_title like CONCAT('%', #{titleOrNum},'%') or b.id = #{titleOrNum})

AND b.product_title like CONCAT('%', #{product_title},'%')
AND b.id = #{product_id}
